args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?year (SUM(CASE WHEN ?country = wd:Q30 THEN 1 ELSE 0 END) * 100.0 / COUNT(*) AS ?percentage)
WHERE {
  ?laureate wdt:P31 wd:Q3203502.
  ?laureate wdt:P585 ?date.
  BIND(SUBSTR(STR(?date), 1, 4) AS ?year)
  FILTER ("1924" <= ?year && ?year <= "2023")
  OPTIONAL { ?laureate wdt:P27 ?country }
}
GROUP BY ?year

